struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Packet ID
        stream.serialise(packet_id);

        // Username with length prefix (Hexi handles length-prefixed strings
        // via its serialise overload for std::string)
        stream.serialise(username);

        // Scores: write count first, then elements via operator<<
        uint32_t count = static_cast<uint32_t>(scores.size());
        stream.serialise(count);
        stream << scores;  // operator<< internally calls write_container

        // Metadata: null-terminated using Hexi's null_terminated adaptor
        stream.serialise(hexi::null_terminated(metadata));
    }
};

