    std::vector<uint8_t> buffer;

    // Create a Hexi output stream that writes into the buffer
    hexi::output_stream<std::vector<uint8_t>> stream(buffer);

    // Use the packet's serialise method
    packet.serialise(stream);

    return buffer;
}
