struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket pkt;

    // Create a reader over the incoming buffer
    hexi::reader r{buffer};

    // 1. Read packet_id
    r.read(pkt.packet_id);

    // 2. Read username using length prefix
    //    Assuming the packet was serialized with a length-prefixed string
    r.read(hexi::prefixed(pkt.username));

    // 3. Read the score count, then the scores vector via read_container
    uint32_t score_count = 0;
    r.read(score_count);
    pkt.scores.resize(score_count);
    r.read_container(pkt.scores);

    // 4. Read metadata string as null-terminated (zero-copy)
    //    We first get a string_view into the buffer, then copy to std::string.
    std::string_view metadata_view;
    r.read(hexi::cstr(metadata_view));
    pkt.metadata.assign(metadata_view.data(), metadata_view.size());

    // 5. Skip any remaining padding bytes (if any)
    if (!r.empty()) {
        r.skip(r.remaining());
    }

    return pkt;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info{};

    hexi::reader r{buffer};

    // 1. Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    std::span<const uint8_t> id_span;
    r.read(hexi::span(id_span));
    // Convert the 4-byte span to uint32_t (assuming native endianness)
    info.packet_id = *reinterpret_cast<const uint32_t*>(id_span.data());

    // 2. Read username using prefixed adaptor to get a string_view
    r.read(hexi::prefixed(info.username));

    // 3. Skip the scores vector without reading its elements:
    //    read the count, then skip count * sizeof(uint32_t) bytes
    uint32_t score_count = 0;
    r.read(score_count);
    std::size_t bytes_to_skip = static_cast<std::size_t>(score_count) * sizeof(uint32_t);
    if (bytes_to_skip > r.remaining()) {
        // If malformed, skip only what remains
        bytes_to_skip = r.remaining();
    }
    r.skip(bytes_to_skip);

    // We do not need metadata or padding for PacketInfo

    return info;
}
