#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};
    result.data_type = 0;

    // Create a buffer adaptor over the input buffer
    hexi::buffer_adaptor adaptor{ buffer.data(), buffer.size() };

    // 1. Preview the first byte (data_type) without advancing the read pointer
    {
        std::size_t available = adaptor.size(); // or adaptor.bytes_available() depending on API
        if (available < sizeof(uint8_t)) {
            // Not enough data even for the type; return default result
            return result;
        }

        // Peek at the first byte; Hexi typically offers a peek/preview method.
        // Assuming API similar to:
        //   std::size_t peek(void* dst, std::size_t bytes);
        uint8_t preview_type = 0;
        adaptor.peek(&preview_type, sizeof(preview_type));
        result.data_type = preview_type;
    }

    // 2. Now use a binary_stream to actually read (this will advance)
    hexi::binary_stream stream{ adaptor };

    // Re-read the data_type, this time consuming it
    uint8_t data_type = 0;
    stream.read(data_type);

    // Check there is enough data for item_count
    std::size_t remaining = adaptor.size(); // still reflects underlying buffer size
    if (remaining < sizeof(uint8_t) + sizeof(uint32_t)) {
        // Not enough data for item_count; return what we have (type only)
        return result;
    }

    // Read item_count
    uint32_t item_count = 0;
    stream.read(item_count);

    // 3. Check that the buffer has enough bytes for all items
    std::size_t bytes_for_items = 0;
    if (data_type == 0) {
        // integers (uint32_t)
