MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    using namespace hexi;

    // Wrap the raw buffer in a buffer_adaptor so we can read typed data
    auto adaptor = buffer_adaptor(buffer);

    // Read the 32-bit header
    uint32_t header = adaptor.read<uint32_t>();

    // Create a binary_stream that views the remaining bytes in the adaptor
    auto stream = binary_stream::view(adaptor.remaining());

    // Find the null terminator in the remaining data
    const auto* begin = stream.data();
    const auto* end   = begin + stream.size();
    const auto* it    = begin;

    while (it != end && *it != 0) {
        ++it;
    }

    // Construct a string_view over the message bytes (excluding the null)
    std::string_view message(
        reinterpret_cast<const char*>(begin),
        static_cast<std::size_t>(it - begin)
    );

    return MessagePacket{header, message};
}
