#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Determine how many bytes are actually readable without consuming
    const std::size_t available = buffer.readable_bytes();
    const std::size_t to_copy   = std::min(available, bytes_to_peek);

    std::vector<uint8_t> result(to_copy);
    if (to_copy == 0) {
        return result;
    }

    // Get the readable regions from the buffer. This does not advance the read pointer.
    auto regions = buffer.readable_regions();

    std::size_t copied = 0;
    for (const auto& region : regions) {
        if (copied >= to_copy) {
            break;
        }

        const std::size_t remaining   = to_copy - copied;
        const std::size_t chunk_size  = std::min(remaining, region.size);

        std::memcpy(result.data() + copied, region.data, chunk_size);
        copied += chunk_size;
    }

    return result;
}
```

