#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>
#include <algorithm>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations.
//
// This function demonstrates that:
//
// 1. allocate() uses the internal pop() to take the head block from the
//    free list. The returned pointer is the current free-list head.
//
// 2. deallocate() uses the internal push() to return a block to the
//    head of the free list. The deallocated pointer becomes the new
//    free-list head.
//
// By observing the sequence of returned pointers and re-used pointers,
// we can infer the LIFO (stack-like) behavior of the internal free list.
template <size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using value_type = std::uint32_t;

    // Create a block allocator that manages `element_count` blocks of value_type.
    // Each allocate() returns a pointer to one block of type value_type.
    hexi::block_allocator<value_type> alloc(element_count);

    std::cout << "Demonstrating block_allocator free list behavior\n";
    std::cout << "Element count (capacity): " << element_count << "\n\n";

    // 1. Allocate several blocks to see how pointers are returned.
    //    Because internal push() builds the initial free list in some
    //    order, pop() (via allocate) will hand them out in LIFO order
    //    relative to that construction.
    constexpr size_t initial_allocs = (element_count < 5 ? element_count : 5);
    std::vector<value_type*> allocated;
    allocated.reserve(initial_allocs);

    std::cout << "Step 1: Initial allocations\n";
    for (size_t i = 0; i < initial_allocs; ++i) {
        value_type* ptr = static_cast<value_type*>(alloc.allocate());
        allocated.push_back(ptr);
        std::cout << "  allocate() #" << i << " -> " << static_cast<void*>(ptr) << "\n";
    }

    std::cout << "\nObservation: The sequence of pointers above reflects the order in which\n"
                 "pop() removes blocks from the internal free list.\n\n";

    // 2. Deallocate in a particular order (not necessarily the same order
    //    they were allocated) to see how pointers are reused. Because
    //    deallocate() uses push() internally, the last deallocated block
    //    should be the first reused on a subsequent allocate().
    std::cout << "Step 2: Deallocate in a mixed order\n";

    // Example deallocation order:
    // - First deallocate the second pointer
    // - Then the last pointer
    // - Finally the first pointer
    if (!allocated.empty()) {
        // Helper lambda for safe deallocation and logging.
        auto do_deallocate = [&](size_t idx) {
            if (idx >= allocated.size() || !allocated[idx])
                return;
            value_type* ptr = allocated[idx];
            std::cout << "  deallocate(" << static_cast<void*>(ptr) << ")\n";
            alloc.deallocate(ptr);
            allocated[idx] = nullptr; // mark as deallocated
        };

        if (allocated.size() >= 2) {
            do_deallocate(1);                     // deallocate second
        }
        if (allocated.size() >= 1) {
            do_deallocate(allocated.size() - 1);  // deallocate last
        }
        do_deallocate(0);                         // deallocate first
    }

    std::cout << "\nObservation: Each deallocate() pushes the block back onto the\n"
                 "free list. The most recently deallocated block becomes the\n"
                 "new free-list head.\n\n";

    // 3. Allocate again to show that the allocator reuses recently
    //    deallocated blocks first (LIFO behavior).
    std::cout << "Step 3: Allocate again to see LIFO reuse\n";
    std::vector<value_type*> reallocated;
    reallocated.reserve(initial_allocs);

    for (size_t i = 0; i < initial_allocs; ++i) {
        value_type* ptr = static_cast<value_type*>(alloc.allocate());
        reallocated.push_back(ptr);
        std::cout << "  allocate() (realloc) #" << i
                  << " -> " << static_cast<void*>(ptr) << "\n";
    }

    std::cout << "\nObservation: The first pointer printed in this step should match the\n"
                 "last pointer that was deallocated in Step 2. This confirms that\n"
                 "allocate() (via internal pop()) takes from the head of the free list,\n"
                 "and deallocate() (via internal push()) inserts at the head.\n\n";

    // 4. Clean up: deallocate everything we have allocated in this function.
    // In a typical usage pattern, callers would be responsible for
    // deallocating what they allocate; we do it here to avoid leaks.
    std::cout << "Step 4: Final cleanup\n";
    for (value_type* ptr : reallocated) {
        if (ptr) {
            std::cout << "  final deallocate(" << static_cast<void*>(ptr) << ")\n";
            alloc.deallocate(ptr);
        }
    }

    std::cout << "\nSummary:\n"
                 "  - allocate() removes the head of the internal free list (pop).\n"
                 "  - deallocate() inserts the block at the head of the free list (push).\n"
                 "  - The free list is therefore managed in a LIFO (stack-like) manner.\n";
}
