```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

// 1. Preview data in an intrusive_storage buffer without advancing the read
//    pointer. This is implemented by temporarily reading into a temporary
//    buffer, then writing the data back so that the storage is restored to
//    its original state.
template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    hexi::detail::intrusive_storage<block_size>& storage,  // non-const to allow restoring
    size_t bytes_to_preview
) {
    std::vector<uint8_t> result;

    // Determine how many bytes are actually readable
    const auto readable = storage.readable_size();
    const auto to_copy  = std::min(bytes_to_preview, readable);
    result.resize(to_copy);

    if (to_copy == 0) {
        return result;
    }

    // 1) Read out the data into result (this advances the read pointer)
    storage.read(result.data(), to_copy);

    // 2) Immediately write it back so that the buffer content is unchanged
    //    and future reads see the same data.
    storage.write(result.data(), to_copy);

    // Note: Depending on intrusive_storage's internal behavior, this may
    //       increase overall size and disturb original layout if the
    //       implementation does not support this pattern. It assumes that
    //       writing back re-appends bytes in a way that restores the
    //       logical read sequence for consumers.

    return result;
}

// 2. Buffer status information
template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

// Check the status of an intrusive_storage<1024> buffer: how many bytes
// are readable and how much space remains free.
BufferStatus<> check_buffer_status(
    const hexi::detail::intrusive_storage<1024>& storage
) {
    BufferStatus<> status{};
    status.readable_size = storage.readable_size();
    status.free_space    = storage.capacity() - storage.size();
    return status;
}

// 3. Reset both read and write offsets.
// This implementation assumes intrusive_storage exposes clear() or an
// equivalent reset/rewind API that resets read/write positions and
// empties the buffer. Adjust to the actual API if different.
template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    storage.clear();  // resets read/write offsets and empties the buffer
}
```

