#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <algorithm> // for std::min

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Open file buffer (read-only by default)
    hexi::file_buffer fb(file_path.string());

    // Save current read position
    auto original_pos = fb.tellg();

    // Determine how many bytes we can actually read
    fb.seekg(0, std::ios::end);
    auto file_size = fb.tellg();
    fb.seekg(original_pos, std::ios::beg);

    size_t readable = 0;
    if (file_size > original_pos) {
        readable = static_cast<size_t>(std::min<std::uintmax_t>(
            static_cast<std::uintmax_t>(header_size),
            static_cast<std::uintmax_t>(file_size - original_pos)
        ));
    }

    std::vector<uint8_t> header(readable);
    if (readable > 0) {
        // Read the header bytes
        fb.read(reinterpret_cast<char*>(header.data()), readable);

        // Restore original position so the read pointer is not advanced
        fb.seekg(original_pos, std::ios::beg);
    }

    return header;
}
