template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                          const std::vector<uint8_t>& data) {
    // Determine how many bytes we can actually write
    const auto writable = std::min(buffer_size, data.size());

    // Write byte-by-byte into the buffer
    for (size_t i = 0; i < writable; ++i) {
        buffer[i] = static_cast<std::byte>(data[i]);
    }
}

template<size_t buffer_size = 1024>
