                                           size_t bytes_to_read) {
    // Clamp read size to buffer capacity
    const auto readable = std::min(buffer_size, bytes_to_read);

    std::vector<uint8_t> result;
    result.reserve(readable);

    for (size_t i = 0; i < readable; ++i) {
        result.push_back(static_cast<uint8_t>(buffer[i]));
    }

    return result;
}
