void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::size_t bytes) {
    // Read and discard `bytes` bytes from the buffer.
    // We use a small temporary buffer and loop until we've skipped all bytes.
    std::byte tmp[256];

    std::size_t remaining = bytes;
    while (remaining > 0) {
        const std::size_t chunk = remaining < sizeof(tmp) ? remaining : sizeof(tmp);
        buffer.read(tmp, chunk);  // discard data
        remaining -= chunk;
    }
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    MessageHeader header{};
    std::byte raw_header[sizeof(MessageHeader)];

    // Read the header bytes from the buffer.
    buffer.read(raw_header, sizeof(raw_header));

    // Copy raw bytes into the header structure.
    // This assumes the serialized layout matches MessageHeader exactly
    // (same endianness, packing, etc.).
    std::memcpy(&header, raw_header, sizeof(header));

    // Skip the body data based on the header's body_length field.
    skip_bytes_in_buffer(buffer, header.body_length);

    return header;
}
