#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits>

using namespace hexi::detail;

// Standard unsigned LEB128-style varint encoding.
// Works for unsigned and signed integral types by encoding the value as
// its unsigned representation (two's complement for signed types).
template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    static_assert(std::is_integral<T>::value, "encode_varint requires integral type");

    using U = typename std::make_unsigned<T>::type;
    U v = static_cast<U>(value);

    std::size_t bytes_written = 0;

    // Emit 7 bits per byte, MSB is continuation flag.
    while (true) {
        std::uint8_t byte = static_cast<std::uint8_t>(v & 0x7fu);
        v >>= 7;
        if (v != 0) {
            byte |= 0x80u;  // continuation bit
        }
        writer.write(byte);
        ++bytes_written;
        if (v == 0) {
            break;
        }
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    static_assert(std::is_integral<T>::value, "decode_varint requires integral type");

    using U = typename std::make_unsigned<T>::type;
    U result = 0;
    std::size_t shift = 0;

    while (true) {
        std::uint8_t byte = 0;
        reader.read(byte);

        result |= (static_cast<U>(byte & 0x7fu) << shift);
        if ((byte & 0x80u) == 0) {
            break;
        }

        shift += 7;
    }

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    static_assert(std::is_integral<T>::value, "encode_decode_roundtrip requires integral type");

    std::vector<std::uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);
    hexi::pmc::binary_stream_writer writer(adaptor);

    encode_varint(writer, original_value);

    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    T decoded = decode_varint<T>(reader);
    return decoded == original_value;
}
