```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

// Check if two memory regions [src, src + src_len) and
// [dst, dst + dst_len) overlap in memory.
bool check_regions_overlap(const void* src, std::size_t src_len,
                           const void* dst, std::size_t dst_len) {
    // Treat nullptr with zero length as empty, which never overlaps.
    if ((!src && src_len == 0) || (!dst && dst_len == 0)) {
        return false;
    }

    // If either length is zero, there is no overlap.
    if (src_len == 0 || dst_len == 0) {
        return false;
    }

    // Cast to byte pointers for pointer arithmetic
    const unsigned char* src_begin = static_cast<const unsigned char*>(src);
    const unsigned char* dst_begin = static_cast<const unsigned char*>(dst);

    // Compute end pointers (one past last byte)
    const unsigned char* src_end = src_begin + src_len;
    const unsigned char* dst_end = dst_begin + dst_len;

    // Two half-open intervals [a,b) and [c,d) overlap iff:
    // a < d && c < b
    return (src_begin < dst_end) && (dst_begin < src_end);
}

// Safely copy memory between regions if they do not overlap.
// Returns true on success, false if regions overlap or input is invalid.
bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Null destination is always invalid for nonzero length.
    if (!destination && length != 0) {
        return false;
    }
    // Null source is invalid for nonzero length.
    if (!source && length != 0) {
        return false;
    }

    // If length is zero, nothing to copy but it's "safe".
    if (length == 0) {
        return true;
    }

    // Check for overlap using the helper
    if (check_regions_overlap(source, length, destination, length)) {
        return false;
    }

    // Perform the copy; regions are guaranteed non-overlapping here.
    std::memcpy(destination, source, length);
    return true;
}
