struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    using namespace hexi;

    buffer buf;

    // Serialize packet_id as a varint
    buf << varint(packet.packet_id);

    // Serialize tags using prefixed_varint:
    // First, the number of tags as a varint-prefixed length
    buf << prefixed_varint(packet.tags.size());

    // Then each tag as a prefixed_varint string
    for (const auto& tag : packet.tags) {
        buf << prefixed_varint(tag);
    }

    // Serialize data as a prefixed_varint string
    buf << prefixed_varint(packet.data);

    // Extract the underlying storage as a contiguous byte vector
    const auto& storage = buf.storage();
    return std::vector<uint8_t>(storage.begin(), storage.end());
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    using namespace hexi;

    CompactPacket packet;

    // Wrap the span in a buffer_view for reading
    buffer_view view(buffer.data(), buffer.size());

    // Deserialize packet_id as a varint
    view >> varint(packet.packet_id);

    // Read number of tags (length encoded via varint)
    std::size_t tags_count = 0;
    view >> prefixed_varint(tags_count);

    packet.tags.clear();
    packet.tags.reserve(tags_count);

    // Read each tag string via prefixed_varint
    for (std::size_t i = 0; i < tags_count; ++i) {
        std::string tag;
        view >> prefixed_varint(tag);
        packet.tags.push_back(std::move(tag));
    }

    // Read data string via prefixed_varint
    view >> prefixed_varint(packet.data);

    return packet;
}
