    writer.writeBytes(reinterpret_cast<const uint8_t*>(packet.data.data()),
                      packet.data.size());

    // Write exactly 16 bytes of padding filled with 0x00
    writer.fill<16>(0x00);

    // Write footer (uint32_t)
    writer.write(packet.footer);

    // Return the underlying buffer
    return writer.buffer();
}

